/**
 * ScratchEditor — редактор Scratch на TurboWarp.
 * /scratch/edit       — новый проект (пустой шаблон)
 * /scratch/edit/:id   — редактируем существующий (загружаем .sb3 в редактор)
 *
 * Workflow для V1:
 * - Iframe TurboWarp /editor с pre-filled URL (сделанным из blob нашего проекта)
 * - Пользователь работает в редакторе
 * - Кнопка «💾 Сохранить» — открывает download .sb3 в TurboWarp UI (File → Save to your computer)
 * - Затем кнопка «✅ Зафиксировать в платформе» — пользователь выбирает скачанный файл, мы делаем upload
 *
 * V2 (потом): hosted scratch-gui npm + прямой save через VM API.
 */

import { useEffect, useRef, useState } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { BASE } from '../api/client'
import { getAccessToken } from '../lib/authStorage'
import {
  getScratchProject, createScratchProject, updateScratchProject,
  submitScratchProject, type ScratchProjectDto,
} from '../api/scratchProjects'

export default function ScratchEditor() {
  const navigate = useNavigate()
  const { id } = useParams<{ id?: string }>()
  const { toast, show } = useToast()
  const fileInputRef = useRef<HTMLInputElement>(null)

  const [project, setProject] = useState<ScratchProjectDto | null>(null)
  const [title, setTitle] = useState('Новый проект')
  const [submitting, setSubmitting] = useState(false)

  // The TurboWarp embed URL — supports `?project_url=...` to load remote .sb3
  const editorUrl = project
    ? `https://turbowarp.org/editor.html?project_url=${encodeURIComponent(`${BASE}/scratch-projects/${project.id}/file?token=${getAccessToken() ?? ''}`)}`
    : `https://turbowarp.org/editor.html`

  useEffect(() => {
    if (!id) return
    getScratchProject(id)
      .then(({ project: p }) => { setProject(p); setTitle(p.title) })
      .catch(() => show('Проект не найден', 'error'))
  }, [id])

  async function handleSaveAs() {
    const file = fileInputRef.current?.files?.[0]
    if (!file) { show('Выбери .sb3 файл (скачай из редактора через File → Save to your computer)', 'error'); return }
    if (!file.name.endsWith('.sb3')) { show('Нужен .sb3 файл', 'error'); return }
    setSubmitting(true)
    try {
      const fd = new FormData()
      fd.append('file', file)
      fd.append('title', title)
      if (project) {
        await updateScratchProject(project.id, fd)
        show('Сохранено', 'success')
      } else {
        const created = await createScratchProject(fd)
        show('Создано', 'success')
        navigate(`/scratch/edit/${created.id}`, { replace: true })
        setProject(created)
      }
      if (fileInputRef.current) fileInputRef.current.value = ''
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setSubmitting(false)
    }
  }

  async function handleSubmit() {
    if (!project) { show('Сначала сохрани проект', 'error'); return }
    try {
      const updated = await submitScratchProject(project.id)
      setProject(updated)
      show('Сдано на проверку 🎉', 'success')
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  return (
    <PlatformShell>
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div style={{ display: 'flex', flexDirection: 'column', height: 'calc(100vh - 0px)' }}>

        {/* Top bar */}
        <div style={{ padding: '10px 16px', background: 'var(--ink, #15141b)', color: '#fff', display: 'flex', gap: 12, alignItems: 'center', flexWrap: 'wrap' }}>
          <button className="kb-btn" style={{ background: 'transparent', color: '#fff', border: '1px solid #fff' }} onClick={() => navigate('/scratch')}>
            ← К моим проектам
          </button>
          <input value={title} onChange={(e) => setTitle(e.target.value)}
            style={{ flex: 1, minWidth: 160, padding: '6px 10px', borderRadius: 6, border: '1px solid #444', background: 'rgba(255,255,255,0.1)', color: '#fff', fontSize: 14, fontWeight: 700 }}
            placeholder="Название проекта" />
          <input ref={fileInputRef} type="file" accept=".sb3" style={{ display: 'none' }} />
          <button className="kb-btn" onClick={() => fileInputRef.current?.click()}>
            📂 Выбрать .sb3
          </button>
          <button className="kb-btn" style={{ background: '#FF9454', color: '#fff', fontWeight: 800 }} disabled={submitting} onClick={() => void handleSaveAs()}>
            {submitting ? '…' : '💾 Сохранить'}
          </button>
          {project && !project.submittedAt && (
            <button className="kb-btn" style={{ background: '#059669', color: '#fff', fontWeight: 800 }} onClick={() => void handleSubmit()}>
              ✅ Сдать учителю
            </button>
          )}
          {project?.submittedAt && (
            <span style={{ fontSize: 13, color: '#9FE8C7', fontWeight: 700 }}>✓ Сдан</span>
          )}
        </div>

        {/* Instructions banner */}
        <div style={{ padding: '8px 16px', background: 'var(--violet-soft, #f3f0ff)', fontSize: 12, color: 'var(--ink)', lineHeight: 1.5 }}>
          💡 Как сохранить: в редакторе сверху <b>Файл → Сохранить на ваш компьютер</b> → скачается .sb3 →
          вверху страницы <b>📂 Выбрать .sb3</b> → выбери скачанный файл → <b>💾 Сохранить</b>.
        </div>

        {/* Editor iframe */}
        <iframe
          src={editorUrl}
          style={{ flex: 1, width: '100%', border: 'none', minHeight: 600 }}
          title="Scratch редактор"
          allow="autoplay; fullscreen"
        />
      </div>
    </PlatformShell>
  )
}
